class ReportGeneratorService
  def initialize(user, date_range)
    @user = user
    @date_range = date_range
  end

  def generate_csv
    posts = Post.where(author: @user, created_at: @date_range)
    CSV.generate do |csv|
      csv << ['Title', 'Published', 'Views']
      posts.each { |p| csv << [p.title, p.published_at, p.view_count] }
    end
  end
end
